// layouts/default/DefaultLayout.js
import { Component } from '@odoo/owl'

export default class DefaultLayout extends Component {
  static template = 'DefaultLayout'
}

import { Component } from '@odoo/owl'

export default class DashboardPage extends Component {
  static template = 'DashboardPage'
  static layout = 'admin'   // uses AdminLayout
}

import { Component } from '@odoo/owl'

export default class IndexPage extends Component {
  static template = 'IndexPage'
  // No layout set → 'default' layout is used automatically
}

import { registerLayout, setDefaultLayout, getLayout } from 'metaowl'

// Register a layout manually
registerLayout('admin', AdminLayout)

// Change the default layout
setDefaultLayout('admin')

// Get a layout component by name
const Layout = getLayout('admin')

export default class LoginPage extends Component {
  static template = 'LoginPage'
  static layout = false   // full-screen, no layout
}
